const HEALTH_CALCS: HealthCalcEntry[] = [
  { name: 'Brake Health V2 (Canonical Evidence-Based Refactor)', icon: Disc, inputs: ['BrakeEvidence rows (MANUAL_MEASUREMENT/WORKSHOP_REPORT/AI_UPLOAD/SERVICE_INVOICE/INSPECTION_PROTOCOL/DTC_SIGNAL/BRAKE_WEAR_SENSOR/TELEMATICS_ESTIMATION) — real mm only from trusted sources', 'Brake lifecycle events (inspection/pads/discs/fluid/full) with optional measured snapshot', 'TripDrivingImpact rows since anchor (canonical temporal wear exposure) + harsh-brake rate/100km', 'VehicleDrivingImpactCurrent only as uncovered-gap fallback', 'Vehicle master (fuelType, brakeForceFrontPercent)', 'Odometer progression', 'Latest BRAKE_SERVICE event'], algorithm: 'V4.8.2: ONE shared rule set lives in brakes/brake-status.ts (pure functions) — BrakeHealthService, BrakeCriticalDetector, Rental Health and AI Health Care call into it, no second brake threshold definition. The wear MODEL math stays (achsweise front/rear: Pads base=usable_mm/70k, Discs 2.0mm/90k, rate = base × bias × usage × stopDensity × hardBrake × fullBraking × reku × k (+highSpeed+thermal for discs), accumulated per trip since anchor, rolling only for uncovered gaps) and drives remaining-km. STATUS is decoupled: classifyEstimatedCondition caps a pure estimate at WARNING; classifyMeasuredThickness / fluid / disc-doc / DTC / immediate-replacement can be CRITICAL. overallCondition = aggregateBrakeCondition(front, rear, systemSafety) with CRITICAL-wins, UNKNOWN ignored. Harsh braking ONLY scales a wear multiplier (0–1/100km 1.00x · 1–3 1.15x · 3–6 1.35x · 6+ 1.60x, configurable) — never a CRITICAL by itself. Honesty-first: measurement/document/sensor = truth, projection = ESTIMATED; dataBasis (MEASURED/DOCUMENTED/SENSOR/ESTIMATED/UNKNOWN) + confidence (HIGH/MEDIUM/LOW/UNKNOWN, day/km gated, estimate never HIGH) never present an estimate as a measurement; remaining life is always a confidence-widened [min,max] range, never false precision. BrakeEvidence is the canonical observation store (BrakeEvidenceService) — TELEMATICS_ESTIMATION can never carry real mm; AI-upload writes confirmed evidence on apply. All thresholds central in brake-health.config.ts (conditionBands, confidenceLevels, remainingKmRange, inspection, harshBraking, measurementFreshness).', output: 'Canonical read model (single source of truth): overallCondition + front/rearAxleCondition (GOOD/WATCH/WARNING/CRITICAL/UNKNOWN), dataBasis + front/rearDataBasis, confidenceLevel + front/rearConfidence, estimatedFront/RearRemainingKmMin/Max (range), nextInspectionRecommendedInKm, estimatedReplacementDueInKm, reasons[], recommendations[], openAlerts[] (canonical codes BRAKE_PAD_WARNING/CRITICAL, BRAKE_SYSTEM_DTC, BRAKE_FLUID_WARNING, BRAKE_INSPECTION_OVERDUE, BRAKE_HEALTH_LOW_CONFIDENCE), lastMeasurement/Service At+MileageKm — plus legacy pads/discs health, limitingComponent, remainingKm, stateClass, coverage kept for back-compat. Consumed by Vehicle Detail (Quick Box + Detail Modal), Fleet Condition tile/detail, Rental Health (evaluateBrakes), AI Health Care and the BRAKE_CRITICAL dashboard insight (estimate caps WARNING, CRITICAL only with a real signal). Runtime consumers use /brake-health/summary + /brake-health/detail.', color: 'text-red-400' },
  { name: 'Tire Health V2 (Canonical Lifecycle + Wear Model + Canonical Status)', icon: Disc, inputs: ['Canonical tire lifecycle commands (install, rotate, replace single/axle/full, activate stored set)', 'Canonical recordMeasurement pipeline (manual/workshop/ai_confirmed/calibration)', 'AI tire spec + tire condition + setup metadata', 'Driving Impact Engine V1', 'Vehicle master data', 'Trip temperature + speed', 'DIMO tire pressure (numeric) + HM pressure freshness/status context', 'k-factor calibration + regression data points', 'DOT code (tire age)'], algorithm: 'V4.8.1: ONE shared rule set lives in tires/tire-status.ts (pure functions) — TireHealthService, TireCriticalDetector and every consumer call into it, no second tire threshold definition. Tread STATUS is mm-based + season-aware (Summer/All-Season GOOD>4.0·WATCH>3.0·WARNING>1.6·CRITICAL≤1.6; Winter GOOD>5.0·WATCH>4.0; legal min 1.6mm always CRITICAL) and decoupled from the wear MODEL math (base × axle × usage × behavior × temperature × pressure × load × seasonMismatch × regen × k × interaction) which still drives remaining-km. overallStatus = aggregateTireStatus(tread, remainingKm, season, unevenWear, pressure, age) with CRITICAL-wins and UNKNOWN ignored. Honesty-first: measurement = truth, projection = estimate → displayMode (MEASURED/ESTIMATED/UNKNOWN) + confidence (HIGH/MEDIUM/LOW/UNKNOWN, day/km gated) never present an estimate as a measurement; no active setup → UNKNOWN + recommendation. Season is month-based (configurable seasonCalendar), pressure honesty-first (stale/incomplete → neutral fallback). All thresholds central in tire-health.config.ts (treadStatusBands, confidenceLevels, measurementFreshness, tireAge, seasonCalendar). Every write routes through TireLifecycleService, emitting coherent TireEvent/TirePositionHistory; active setup = status=ACTIVE + removedAt=null.', output: 'Canonical read model (single source of truth): overallStatus (GOOD/WATCH/WARNING/CRITICAL/UNKNOWN), displayMode, confidence, lowestTreadMm + lowestTreadPosition, measuredTreadMm/estimatedTreadMm/displayTreadMm, lastMeasurementAt, measurementAgeDays, estimatedRemainingKm, pressureStatus, seasonStatus, unevenWearStatus, recommendations, alerts (canonical codes TIRE_TREAD_LOW/CRITICAL, TIRE_PRESSURE_LOW/HIGH, TIRE_SEASON_MISMATCH, TIRE_AGE_WARNING, TIRE_MEASUREMENT_OVERDUE, TIRE_WEAR_UNEVEN, TIRE_ROTATION_RECOMMENDED) — plus legacy overallPercent/actionState/measurementState/pressureContext kept for back-compat. Consumed by Vehicle Detail (Quick Box + Detail Modal), Fleet Condition tile/detail, Dashboard Vehicle-Health box, HealthSummaryService (via getSummary) and the TIRE_CRITICAL dashboard insight.', color: 'text-amber-400' },
  { name: 'Oil Health', icon: Droplet, inputs: ['Oil life signal', 'Mileage since change', 'Engine hours'], algorithm: 'Decay from last change + signal', output: 'Oil life %, next change estimate', color: 'text-yellow-400' },
  { name: 'Battery (HV)', icon: Battery, inputs: ['Provider-reported DIMO SOH evidence', 'Document/manual/workshop SOH evidence (BatteryEvidence)', 'HV telemetry snapshots (SoC/range/temperature/charging state/power/current energy/gross capacity)', 'Energy throughput between SoC readings', 'Nominal capacity from vehicle master'], algorithm: 'V4.8.0: canonical precedence is provider_reported SOH (fresh) → reported SOH (document/manual/workshop) → telemetry_derived capacity/energy measurement. The age/km degradation fallback was REMOVED — when no reliable basis exists HV SOH is unavailable/unknown (status estimate_unavailable, noFallbackSoh:true), never a fabricated percentage and never an alert basis. SOH bands (shared battery-status.ts, distinct from LV): ≥80 GOOD · 70–79 WATCH · 60–69 WARNING · <60 CRITICAL. Publication still runs through EWMA + hysteresis (HvBatteryHealthCurrent); evidence persisted in BatteryEvidence with observedAt/source provenance. Current battery telemetry stays explicitly separated from health.', output: 'Canonical hv section: healthStatus (GOOD/WATCH/WARNING/CRITICAL/UNKNOWN), sohPct + healthPercent, sohSource (PROVIDER/CAPACITY_ESTIMATE/DOCUMENT/MANUAL), noFallbackSoh, method, evidenceType, freshness, publication state, telemetry context, charging sessions, trend and interpretation', color: 'text-emerald-400' },
  { name: 'Battery (LV) V2 — Estimated Battery Health', icon: Battery, inputs: ['DIMO lowVoltageBatteryCurrentVoltage (+ source timestamp)', 'Rest voltage (RESTING context, engine-off)', 'Crank drop + recovery', 'Rest stability', 'VehicleBatterySpec.batteryType (lead-acid/AGM/EFB/lithium)', 'Document-confirmed LV workshop measurements'], algorithm: 'V4.8.0: LV is no longer a workshop SOH — it is behaviour-derived „Estimated Battery Health". The rigid voltage→SOH table was REMOVED (legacy BatteryHealthService persists raw measurements only, sohPercent=null). Two separate signals, classified by the shared battery-status.ts rule set: (A) Estimated Battery Health from the V2 publication pipeline (raw → EWMA/stabilized → published with hysteresis) → 80–100 GOOD · 60–79 WATCH · 40–59 WARNING · 0–39 CRITICAL → rendered as a 3-bar indicator, never an SOH %. (B) Resting Voltage with battery-spec-aware bands: UNKNOWN/LEAD_ACID/EFB ≥12.50 Good/≥12.20 Watch/≥12.00 Warning/<12.00 Critical, AGM ≥12.60/≥12.30/≥12.10, LITHIUM = UNSUPPORTED (no lead-acid alerts); only a genuine RESTING voltage is used, never a live/charging voltage. Final lv.healthStatus aggregates both (CRITICAL>WARNING>WATCH>GOOD; UNKNOWN only without any usable signal); legacy lv.condition is derived from it. Runtime states (ready/calibrating/stabilizing/no_recent_data/estimate_unavailable) and calibration blockers preserved. BatteryCriticalDetector consumes the same rules and only alerts on WARNING/CRITICAL (resting WARNING needs two consecutive qualified measurements; CRITICAL fires immediately).', output: 'Canonical lv section: healthStatus, estimatedHealth {status, scorePct (internal), displayMode:BARS, bars 0–3, label „Estimated Battery Health", confidence, calibrationStatus}, restingVoltage {valueV, status, thresholdSource BATTERY_SPEC/DEFAULT/UNSUPPORTED, batteryType, measurementContext}, condition (good/watch/attention), method, freshness, calibration progress, telemetry + evidence provenance, watchpoints + recommendations', color: 'text-cyan-400' },
  { name: 'Error Codes (DTC)', icon: Wrench, inputs: ['obdDTCList signal (DIMO)', 'Poll freshness timestamp', 'Active vs cleared state diff', 'Occurrence count'], algorithm: 'Poll every 3 h → diff active codes → clear disappeared → stale if > 6 h since last success', output: 'status (clean/active_faults/stale/unavailable), activeFaultCount, lastSuccessfulCheckAt, history', color: 'text-violet-400' },
  { name: 'Driving Impact Engine V1 (shared layer)', icon: Layers, inputs: ['VehicleTrip: distanceKm, city/highway/country%, hardAccelCount, hardBrakeCount, fullBrakingCount, kickdownCount, brakingEventCount', 'SMART5/UNKNOWN: TripBehaviorEvent (peakDecelMs2, startSpeedKmh, endSpeedKmh, classification)', 'LTE_R1: DrivingEvent (source=TELEMETRY_EVENTS, severity-based peak decel proxy)', 'Speeding exposure signals (speedingExposurePct, maxOverSpeedKmh, avgOverSpeedKmh, speedingSectionCount)'], algorithm: 'V3 hardware-aware ingestion: branches on hardwareType. Per-100km normalization + weighted stress scores (longitudinal/braking/stop-go/high-speed/thermal) + distance-weighted 30-day rolling aggregate. V4.6.83: two canonical 0–100 scalars per trip — drivingStyleScore (via reference-deduction over the stress components) and safetyScore (via single central computeSafetyScore(speedingExposurePct, max/avg overspeed, sectionCount))', output: 'TripDrivingImpact (per trip): 5 stress scores, usage split, per-100km rates, p95 decel, meanBrakeEnergy, drivingStyleScore, safetyScore. VehicleDrivingImpactCurrent (per vehicle): rolling 30-day distance-weighted average of all metrics including rolling drivingStyleScore AND rolling safetyScore (V4.6.83) — consumed by Tire Health V2, Brake Health V2, vehicle-level score cards. VehicleTrip.drivingScore is a transition-compatible mirror of drivingStyleScore only.', color: 'text-orange-400' },
  { name: 'AI Tire Spec Agent', icon: Disc, inputs: ['User-provided: tire brand, model, dimension (size), load index, speed index', 'Vehicle year from master data', 'Available in: Vehicle Registration Modal + Health Errors View'], algorithm: 'V4.2.4: SSE streaming via DIMO Agent from registration form. Stream timeout 300s + 120s inactivity detection. Prompt is knowledge-based (no web search) for fast response. Requests 55+ fields (EU label, UTQG, dimensional, bias/sensitivity, OE markings). Data mapping: legalMinTreadDepthMm→legalMinimumMm, practicalReplacementDepthMm→recommendedReplacementDepthMm for wear model. Result shown in collapsible preview table. On registration: AI tire spec JSON stored alongside typed load/speed index columns.', output: 'AI tire spec JSON on VehicleTireSetup.aiTireSpec. DB columns: load_index_front, speed_index_front, load_index_rear, speed_index_rear, dot_code_front, dot_code_rear. Fields: matchedBrand/Model/Variant, seasonType, EU label classes, UTQG ratings, newTreadDepthMm, practicalReplacementDepthMm, bias/sensitivity values (0-1), confidenceScore (0-1), source URLs. Metadata: userConfirmedSpec, specSourceType, fetchedAt, jobId. Manual tread/calibration never touched. Consumed by Tire Health V2 wear engine for model-aware baseline and factor tuning.', color: 'text-purple-400' },
  { name: 'AI Assistant (Chat Agent) — V4.9.2 SSE', icon: Zap, inputs: ['User chat message (rental AIAssistantView)', 'Per-org DIMO chat agent (OrganizationChatAgent: agentName=<shortCode>_chatagent, dimoAgentId)', 'Fleet context: registered vehicles (make/model/year, plate, name, VIN, DIMO tokenId, fuel) injected per message + license-plate/name/make-model/VIN/tokenId resolution hint', 'DIMO Agents API (agents.dimo.zone), Developer-JWT Bearer + DIMO_API_KEY/USER_WALLET in agent secrets'], algorithm: 'V4.9.2: the chat runs over the DIMO SSE stream endpoint POST /agents/:id/stream (DimoAgentsService.sendMessageStream), NOT the synchronous /agents/:id/message which returns 504 for any request that requires real agent work (tool calls / telemetry lookups). Flow: Frontend streamChatMessage (POST fetch + ReadableStream reader, Authorization header) → ChatController POST /organizations/:orgId/chat/message/stream (SSE: text/event-stream, X-Accel-Buffering:no, RolesGuard) → ChatService.streamMessage: ensureAgent (create+persist per-org agent if missing, auto shortCode) → save user ChatMessage → build fleet-enriched prompt + tokenIds → sendMessageStream with onChunk forwarding live progress (reasoning/tool_call/tool_return labels) as SSE `progress` events → on agent expiry (404/410) recreate agent once and retry → persist assistant ChatMessage → emit final `result`. SSE events: status / progress / result / error. The non-streaming ChatService.sendMessage (used by WhatsApp AI suggestions) was also moved onto the stream path, so it is 504-fest too. Sibling agent consumers (AI Upload = DimoDocumentAgentService, DTC research = DtcAiResearchService, vehicle/tire specs) already used sendMessageStream — unchanged.', output: 'Persisted ChatMessage rows (role user/assistant, organizationId-scoped) returned via GET /chat/history; live assistant answer streamed to AIAssistantView with a live "thinking"/tool-step indicator. No fabricated fleet facts — fleet context only resolves which vehicle the user means.', color: 'text-purple-400' },
];

