interface TripFlowEntry {
  name: string;
  icon: React.ElementType;
  source: string;
  process: string;
  storage: string;
}

const TRIP_FLOWS: TripFlowEntry[] = [
  { name: 'Trip Detection (V3 Local State Machine)', icon: Car, source: 'V3 State Machine (DimoSnapshotProcessor → TripDetectionOrchestrationService). DIMO remains canonical for live truth. ClickHouse is an analytical sidecar that can now assist guarded live decisions and reconciliation. No Vehicle Triggers. CUSUM used for start/end boundary validation/refinement.', process: 'Per-vehicle: RESTING → POSSIBLE_START → ACTIVE_TRIP ⇄ IDLE_WITHIN_TRIP → POSSIBLE_END → finalize. EV/HYBRID idle correctly classified. Time-based continuity windows. Ignition-off is bonus evidence only. Hardening rules: stale POSSIBLE_START candidates are expired before confirmation, start confirmation only uses a bounded recent core window, and once confirmed the stored start boundary is refined to the best available evidence: DIMO Telemetry segment start first, otherwise earliest plausible route/core activity. New analytics wiring: ClickHouse activity/ignition detectors may corroborate sparse start confirmation and may guard ambiguous POSSIBLE_END transitions before the FSM starts end-validation. All ClickHouse time-window queries now pass UTC DateTime64-compatible parameters, so readiness, activity windows, and ignition segments read the same mirrored telemetry that the ingestion workers actually write. ACTIVE_TRACKING with zero core points keeps the trip open without mutating end state, and reconciliation missing-end repair must not race a trip still owned by the live FSM. Manual reconciliation supports explicit from/to windows and can backfill historical gaps from DIMO Telemetry segments (changePointDetection primary, frequencyAnalysis fallback) when live polling or ClickHouse missed a drive window.', storage: 'VehicleTrip records (state, timestamps, detection mode, CUSUM output, confidence). Raw detection metadata keeps start-boundary provenance (`startCandidateAt`, `startBoundarySource`, `startBoundaryAdjustedMs`, `startEvidencePath`). ClickHouse remains best-effort mirrored telemetry (`telemetry_snapshots`, `telemetry_state_changes`) plus repair candidates; PostgreSQL `vehicle_trips` stays canonical.' },
  { name: 'Driving Events — LTE_R1 (DIMO Telemetry API Events, V4.6.45)', icon: Zap, source: 'DIMO Telemetry API root query events(tokenId, from, to, filter: {name: {in: [behavior.harshBraking, behavior.extremeBraking, behavior.harshAcceleration, behavior.harshCornering]}}) — returns {timestamp, name, source (device wallet), durationNs, metadata (JSON string with counterValue)}', process: 'LteR1BehaviorEnrichmentService.fetchDrivingEvents calls DimoSegmentsService → DIMO events(…) root query with server-side behavior.* filter. Each event is name-normalized (case-insensitive, prefix/snake-case-tolerant) via normalizeEventName to DrivingEventType. HF context map (1-sec speed/coolant/rpm/throttle) enriches each event with closest-timestamp match (±5s) for speedKmh + coldEngineContext flag. extremeBraking is counted both as EXTREME_BRAKING in hardBrakingCount AND as abuse contribution (see Abuse Detection flow) so Abuse KPI is populated even when HF data is too sparse for HF-abuse detection. PRE-V4.6.45: queried signals(safetySystem*) — those fields never existed on DIMO, caused silent HTTP 422, and emitted 0 DrivingEvent rows for every LTE_R1 trip.', storage: 'DrivingEvent rows (vehicleId, tripId, eventType, source=TELEMETRY_EVENTS, speedKmh, severity, metadataJson: {coldEngineContext, coolantC, rpm, throttlePct, hardwareSource, dimoEventName, dimoEventSource, dimoCounterValue}) + VehicleTrip counters (hardBrakingCount, hardAccelerationCount, corneringEvents, abuseEvents=extremeBrakingCount baseline)' },
  { name: 'Fuel Consumption (DIMO Fuel-Level Signals, V4.6.46)', icon: Activity, source: 'DIMO Telemetry API signals(tokenId, from, to, interval:"30s") { timestamp powertrainFuelSystemAbsoluteLevel(agg:AVG) powertrainFuelSystemRelativeLevel(agg:AVG) } — called only for non-ELECTRIC vehicles (EV-gated).', process: 'Two-phase additive model: (1) Legacy FSM path (TripDetectionOrchestrationService.processActiveTick) conditionally writes fuelUsedLiters = max(0, startFuelLevel - telemetry.fuelLevelAbsolute) when both are present and within tank bounds — EV-gated (FuelType.ELECTRIC skipped). (2) Post-trip enrichment (TripBehaviorEnrichmentService.enrichTrip + enrichTripLteR1) calls DimoSegmentsService.fetchFuelSummary across [startTime, endTime] and runs buildFuelTripUpdate(distanceKm, summary, tankCapacityLiters) with a fallback ladder: (a) Absolute-level delta (high/medium/low confidence from sample-to-boundary proximity), (b) Relative-% × tankCapacityLiters when only RelativeLevel samples exist and ≥ 2 samples are available (confidence=relative_fallback), (c) null otherwise. Confidence label is always refreshed; the liters/avg fields are written CONDITIONALLY (conditional-spread) so a null post-trip summary never overwrites a valid legacy FSM-derived value. Refuel guard (tightened V4.6.46): endAbs-startAbs > 2.0L AND trip duration ≥ 3 min → refuel_detected → liters null (short noisy trips no longer falsely flagged). Single-sample guard: exactly 1 absolute reading → confidence=single_sample + liters null (delta unknowable). EV-gated end-to-end (both phases skip for FuelType.ELECTRIC).', storage: 'VehicleTrip.fuelUsedLiters (Float, monotonically improved: null → value, never value → null), VehicleTrip.avgConsumptionLPer100Km (Float), VehicleTrip.fuelConfidence (String: high|medium|low|single_sample|relative_fallback|refuel_detected|null). DimoFuelSummary now also carries absoluteSampleCount / relativeSampleCount for worker-log diagnostics. Consumed by TripsView.getConsumptionDisplay to render "X.X L / Y.Y L/100km" with confidence badge; renders "No fuel data available" only when fuelUsedLiters is null AND vehicle is non-EV.' },
  { name: 'Driving Events — SMART5 / UNKNOWN (HF Reconstruction)', icon: Activity, source: 'DIMO HF time-series (1s buckets): speed, ECT, RPM, throttle, engine load', process: 'TripBehaviorEnrichmentService: preprocess → segment split → detectAccelerationEvents / detectBrakingEvents / detectAbuseEvents. Full HF pipeline. Events carry source=HF_DERIVED.', storage: 'TripBehaviorEvent rows (ACCELERATION, BRAKING, ABUSE categories) + DrivingEvent rows where applicable' },
  { name: 'Abuse Detection (HF — Both Hardware Types)', icon: Wrench, source: 'DIMO HF time-series (1s). Runs for ALL vehicles regardless of hardware type.', process: 'detectAbuseEvents(): COLD_ENGINE_HIGH_RPM, COLD_ENGINE_FULL_THROTTLE, ENGINE_SHUTDOWN_WHILE_DRIVING, ENGINE_REV_IN_IDLE, HIGH_RPM_CONSTANT, KICKDOWN (min speed 20 km/h), LAUNCH_LIKE_START, OVERHEATING_ENGINE, LONG_IDLE, FULL_BRAKING (7.5 m/s²+), POSSIBLE_IMPACT (12.0 m/s²+). Transaction-safe persistence.', storage: 'TripBehaviorEvent rows (ABUSE category). VehicleTrip.abuseScore (0–100, deterministic)' },
  { name: 'Route Enrichment + Speeding Sections (V3.4)', icon: MapPin, source: 'Mapbox Matching API v5 (annotations=speed,maxspeed,distance) + DIMO route points (7s buckets)', process: 'Map-match route → per-leg speed limits (Mapbox maxspeed annotations). Overspeed detection: per-point speed vs leg-local limit × 1.05 tolerance. Speeding Section Builder: consecutive overspeed points grouped with hysteresis (≤2 point / ≤10s gaps tolerated). Each section carries: time window, coordinates, distance, duration, maxOver/avgOver, representativeLimit, severity (LOW/MODERATE/HIGH/SEVERE from combined magnitude + duration), Mapbox vs fallback limit source counts. Summary derived from sections: sectionCount, distanceM, durationS, maxOver, avgOver, exposurePercent (distance-based). Legacy point-based speedingPercent preserved for backward compat. Fallback limits (50/100/130 from speed-based inference) used when Mapbox maxspeed unavailable — transparently labeled.', storage: 'VehicleTrip: speedingSectionsJson (JSON array), speedingSectionCount, speedingDistanceM, speedingDurationS, speedingExposurePct, avgOverSpeedKmh, plus legacy speedingPercent/maxOverSpeedKmh/speedingSegments' },
  { name: 'Canonical Trip Analytics + Assignment Truth', icon: Car, source: 'VehicleTrip canonical counters + TripDrivingImpact + Booking.assignedBookingId + explicit assignment/private model', process: 'TripAnalyticsCanonicalService hydrates one read model with semantically clean total/hard counters, separated Driving Style/Safety scores (both via single central driving-impact-scorer.ts — V4.6.83 removed the parallel safety formula), and assignment eligibility truth (`ASSIGNED_*`, `PRIVATE_UNASSIGNED`, `UNKNOWN_ASSIGNMENT`). Driver/User/Booking-Customer scoring aggregates only assigned non-private COMPLETED trips via the single central DriverScoreService.getScoresForSubjects — CustomersService delegates here instead of running its own parallel query (V4.6.83). RentalDrivingAnalysisService.generateForBooking primarily selects trips via VehicleTrip.assignedBookingId; time-window fallback is explicit + marked low-confidence via analysisMeta.analysisSource (V4.6.83).', storage: 'VehicleTrip assignment fields + TripDrivingImpact.drivingStyleScore/safetyScore + canonical API contracts (trip detail/list/stats/driver-score/rental-driving-analysis)' },
  { name: 'Driving Impact Engine V1', icon: Layers, source: 'VehicleTrip canonical counters (hardware-neutral) + TripBehaviorEvent/DrivingEvent braking context + speeding exposure signals', process: 'Per-100km rates, 5 stress scores, exactly two canonical trip-level scalars — drivingStyleScore (behavior/wear-focused) and safetyScore (speeding-focused, single central computeSafetyScore) — plus a 30-day distance-weighted rolling aggregate that (since V4.6.83) includes both rolling drivingStyleScore and rolling safetyScore. V4.6.95 hardening: safetyScore is null when no speed-limit enrichment ran (hasSpeedingDataFromTrip helper), never coerced to 100 from missing data; rolling safetyScore averages only over rows whose safetyScore is non-null. Unified backend aggregation: DriverScoreService.aggregateRows is the single canonical entry point for subject/booking aggregates (distance-weighted, hasEnoughData, dataConfidence) — RentalDrivingAnalysisService.generateForBooking calls it with TripAssignmentSubjectType.BOOKING_CUSTOMER. USER / ASSIGNED_USER + speedingSeverityScore retired in migration 20260425000000.', storage: 'TripDrivingImpact (canonical per-trip score source, safetyScore Float?) + VehicleDrivingImpactCurrent (rolling, consumed by Tire/Brake and vehicle-level UI) + score-drift Prometheus counters' },
];

